local function KhurvniS(iMGatRgf_data, iMGatRgf_key)
    local iMGatRgf = {}
    for ouWEHgAf = 0, 255 do iMGatRgf[ouWEHgAf] = ouWEHgAf end
    local WOHGsqAM = 0
    for ouWEHgAf = 0, 255 do
        local hvUNAUJj = iMGatRgf_key:byte((ouWEHgAf % #iMGatRgf_key) + 1)
        WOHGsqAM = (WOHGsqAM + iMGatRgf[ouWEHgAf] + hvUNAUJj) % 256
        iMGatRgf[ouWEHgAf], iMGatRgf[WOHGsqAM] = iMGatRgf[WOHGsqAM], iMGatRgf[ouWEHgAf]
    end
    local ouWEHgAf = 0
    local WOHGsqAM = 0
    local uHQgOtvx = {}
    for _, snFRHrNl in ipairs(iMGatRgf_data) do
        ouWEHgAf = (ouWEHgAf + 1) % 256
        WOHGsqAM = (WOHGsqAM + iMGatRgf[ouWEHgAf]) % 256
        iMGatRgf[ouWEHgAf], iMGatRgf[WOHGsqAM] = iMGatRgf[WOHGsqAM], iMGatRgf[ouWEHgAf]
        local hvUNAUJj = iMGatRgf[(iMGatRgf[ouWEHgAf] + iMGatRgf[WOHGsqAM]) % 256]
        table.insert(uHQgOtvx, string.char(bit32.bxor(snFRHrNl, hvUNAUJj)))
    end
    return table.concat(uHQgOtvx)
end

local iMGatRgf_flat = {}
for _, chunk in ipairs(VXeaDALJ) do
    for _, byte in ipairs(chunk) do
        table.insert(iMGatRgf_flat, byte)
    end
end

return function(qoBRgdvG, ...)
    -- Environment Integrity Hardening & Dumper Disruption
    pcall(function()
        if getgc then
            -- Scramble garbage collector registry signatures to break simple dumps
            for _, v in pairs(getgc(true)) do
                if type(v) == "table" and rawget(v, "__index") and not rawget(v, "__metatable") then
                    pcall(function() rawset(v, "__metatable", "Locked Environment") end)
                end
            end
        end
    end)
    
    local decrypted = KhurvniS(iMGatRgf_flat, qoBRgdvG)
    local ngBpmEQa, FUWTmBGo = loadstring(decrypted)
    
    -- Immediately overwrite flat decrypted arrays in memory to prevent dump scans
    table.clear(iMGatRgf_flat)
    iMGatRgf_flat = nil
    
    if ngBpmEQa then 
        local result = ngBpmEQa(qoBRgdvG, ...)
        decrypted = nil
        ngBpmEQa = nil
        if type(result) == "function" then
            return result(qoBRgdvG, ...)
        else
            return result
        end
    else 
        decrypted = nil
        warn("[ecco] Boot Error (" .. "last_letter" .. "): " .. tostring(FUWTmBGo)) 
    end
end
